 .../decider/AwarenessAllocationDecider.java   |  9 +++-
 .../InformationSchemaTest.java                |  4 +-
 .../metadata/sys/SysClusterTableInfoTest.java | 45 +++++++++++++++++++
 7 files changed, 80 insertions(+), 10 deletions(-)

